export const versets = {
  debutant: [
    { question: "'Au commencement, Dieu créa les cieux et la terre.' — Quel livre ?", options: ["Exode", "Genèse", "Jean", "Psaumes"], correct: 1, explanation: "Ce verset ouvre le livre de la Genèse (Genèse 1:1)." },
    { question: "'Car Dieu a tant aimé le monde...' — Quel chapitre et verset ?", options: ["Jean 1:1", "Jean 3:16", "Romains 8:28", "Psaume 23:1"], correct: 1, explanation: "Jean 3:16 est l'un des versets les plus connus de la Bible." },
    { question: "'L'Éternel est mon berger, je ne manquerai de rien.' — Quel Psaume ?", options: ["Psaume 1", "Psaume 19", "Psaume 23", "Psaume 91"], correct: 2, explanation: "Le Psaume 23, écrit par David, commence par ces mots célèbres." },
    { question: "'Je suis le chemin, la vérité et la vie.' — Qui a dit cela ?", options: ["Moïse", "Paul", "Pierre", "Jésus"], correct: 3, explanation: "Jésus a prononcé ces paroles dans Jean 14:6." },
    { question: "'Au commencement était la Parole...' — Quel Évangile ?", options: ["Matthieu", "Marc", "Luc", "Jean"], correct: 3, explanation: "L'Évangile de Jean s'ouvre avec 'Au commencement était la Parole' (Jean 1:1)." },
    { question: "'Je puis tout par celui qui me fortifie.' — Quelle épître ?", options: ["Romains", "Galates", "Philippiens", "Éphésiens"], correct: 2, explanation: "L'apôtre Paul écrit cela dans Philippiens 4:13." },
    { question: "'Confie-toi en l'Éternel de tout ton cœur.' — Quel livre ?", options: ["Psaumes", "Proverbes", "Ecclésiaste", "Cantique des Cantiques"], correct: 1, explanation: "Proverbes 3:5 : 'Confie-toi en l'Éternel de tout ton cœur.'" },
    { question: "'Aime ton prochain comme toi-même.' — Où ce commandement apparaît-il d'abord ?", options: ["Matthieu 22", "Lévitique 19", "Deutéronome 6", "Romains 13"], correct: 1, explanation: "Ce commandement apparaît d'abord dans Lévitique 19:18." },
    { question: "Quel verset dit 'Car c'est par la grâce que vous êtes sauvés, par le moyen de la foi' ?", options: ["Romains 3:23", "Éphésiens 2:8", "Jean 1:12", "Actes 4:12"], correct: 1, explanation: "Éphésiens 2:8 : 'Car c'est par la grâce que vous êtes sauvés, par le moyen de la foi.'" },
    { question: "Complétez Jérémie 29:11 : 'Car je connais les projets que j'ai formés sur vous... des projets de ___' ?", options: ["Gloire", "Paix et non de malheur", "Bonheur et de prospérité", "Justice et de droiture"], correct: 1, explanation: "Jérémie 29:11 : '...des projets de paix et non de malheur, pour vous donner un avenir et de l'espérance.'" },
    { question: "Quel est le verset le plus court de la Bible ?", options: ["'Dieu est amour'", "'Jésus pleura'", "'Réjouissez-vous toujours'", "'Priez sans cesse'"], correct: 1, explanation: "'Jésus pleura' (Jean 11:35) est souvent cité comme le verset le plus court de la Bible." },
    { question: "'La foi, c'est...' — Comment se termine Hébreux 11:1 ?", options: ["...aimer Dieu de tout son cœur", "...la certitude des choses qu'on espère, la démonstration de celles qu'on ne voit pas", "...croire en Christ Jésus", "...obéir à la Parole de Dieu"], correct: 1, explanation: "Hébreux 11:1 : 'Or la foi, c'est la certitude des choses qu'on espère, la démonstration de celles qu'on ne voit pas.'" },
    { question: "'L'amour est donc l'accomplissement de la ___.' (Romains 13:10)", options: ["Foi", "Loi", "Grâce", "Promesse"], correct: 1, explanation: "Romains 13:10 : 'L'amour est donc l'accomplissement de la loi.'" },
    { question: "Dans quel livre : 'Il y a un temps pour tout, un temps pour chaque chose sous le ciel' ?", options: ["Proverbes", "Job", "Ecclésiaste", "Psaumes"], correct: 2, explanation: "Ecclésiaste 3:1 : 'Il y a un temps pour tout, un temps pour chaque chose sous le ciel.'" },
    { question: "Quel apôtre écrit 'Dieu est amour' ?", options: ["Paul", "Pierre", "Jean", "Jacques"], correct: 2, explanation: "Jean écrit 'Dieu est amour' dans 1 Jean 4:8 et 4:16." },
    { question: "Quel verset dit 'Car le salaire du péché, c'est la mort' ?", options: ["Galates 6:7", "Romains 6:23", "Jacques 1:15", "1 Jean 1:8"], correct: 1, explanation: "Romains 6:23 : 'Car le salaire du péché, c'est la mort ; mais le don gratuit de Dieu, c'est la vie éternelle.'" },
    { question: "Quel est le premier verset du Psaume 1 ?", options: ["'L'Éternel est mon berger'", "'Heureux l'homme qui ne marche pas selon le conseil des méchants'", "'Les cieux racontent la gloire de Dieu'", "'De tout mon cœur je te louerai'"], correct: 1, explanation: "Le Psaume 1 commence par 'Heureux l'homme qui ne marche pas selon le conseil des méchants...'" },
    { question: "Quel verset dit 'Réjouissez-vous toujours dans le Seigneur' ?", options: ["1 Thessaloniciens 5:16", "Philippiens 4:4", "Colossiens 3:17", "Romains 12:12"], correct: 1, explanation: "Philippiens 4:4 : 'Réjouissez-vous toujours dans le Seigneur ; je le dis encore, réjouissez-vous.'" },
    { question: "Quel verset conclut la Grande Commission de Matthieu 28 ?", options: ["'Allez, faites de toutes les nations des disciples'", "'Je suis avec vous tous les jours, jusqu'à la fin du monde'", "'Baptisez-les au nom du Père, du Fils et du Saint-Esprit'", "'Enseignez-leur à observer tout ce que je vous ai prescrit'"], correct: 1, explanation: "Matthieu 28:20 se termine par 'Et voici, je suis avec vous tous les jours, jusqu'à la fin du monde.'" },
    { question: "Quel verset de Matthieu résume les deux grands commandements ?", options: ["'Tu aimeras le Seigneur de tout ton cœur, et ton prochain comme toi-même'", "'Bienheureux les doux, car ils hériteront la terre'", "'Priez afin de ne pas tomber en tentation'", "'Ce que vous avez fait au moindre de mes frères, c'est à moi que vous l'avez fait'"], correct: 0, explanation: "Matthieu 22:37-39 résume toute la Loi : aimer Dieu de tout son être + aimer son prochain comme soi-même — cités par Jésus comme les deux grands commandements sur lesquels reposent toute la Loi et les Prophètes." },
    { question: "Complétez Jean 10:10 : 'Le voleur ne vient que pour dérober, égorger et détruire ; moi, je suis venu...' ?", options: ["'...pour sauver le monde'", "'...pour qu'on ait la vie, et pour qu'on l'ait en abondance'", "'...pour appeler les pécheurs à la repentance'", "'...pour accomplir la Loi et les Prophètes'"], correct: 1, explanation: "Jean 10:10 : 'moi, je suis venu pour qu'on ait la vie, et pour qu'on l'ait en abondance.' Ce verset contraste le voleur (Satan) et le bon berger (Christ) — l'abondance de la vie en Christ." },
    { question: "Quel Psaume commence par 'Les cieux racontent la gloire de Dieu' ?", options: ["Psaume 8", "Psaume 19", "Psaume 33", "Psaume 148"], correct: 1, explanation: "Le Psaume 19:2 : 'Les cieux racontent la gloire de Dieu, et l'étendue manifeste l'œuvre de ses mains.'" },
    { question: "Quel est le verset du Psaume 46 souvent traduit 'Dieu est pour nous un refuge et un appui' ?", options: ["Psaume 46:1", "Psaume 46:2", "Psaume 46:10", "Psaume 46:11"], correct: 0, explanation: "Psaume 46:1 (v.2 dans certaines versions) : 'Dieu est pour nous un refuge et un appui, un secours qui ne manque jamais dans la détresse.'" },
    { question: "Complétez Matthieu 5:14 : 'Vous êtes la lumière du monde. Une ville...' ?", options: ["'...éclairée ne peut se cacher'", "'...qui est sur une montagne ne peut être cachée'", "'...lumineuse attire les hommes à Dieu'", "'...de Dieu brille dans les ténèbres'"], correct: 1, explanation: "Matthieu 5:14 : 'Vous êtes la lumière du monde. Une ville qui est sur une montagne ne peut être cachée.' Jésus appelle ses disciples à rayonner leur foi dans le monde." },
    { question: "Quel verset dit 'Cherchez d'abord le Royaume de Dieu et sa justice, et toutes ces choses vous seront données par-dessus' ?", options: ["Matthieu 6:33", "Luc 12:31", "Matthieu 5:6", "Les deux premiers"], correct: 3, explanation: "Matthieu 6:33 et Luc 12:31 reprennent tous deux cet enseignement de Jésus du Sermon sur la Montagne sur la priorité du Royaume de Dieu sur les soucis matériaux." },
    { question: "Quel verset de l'Ancien Testament est le plus souvent cité dans le NT ?", options: ["Genèse 1:1", "Psaume 110:1", "Isaïe 53:5", "Deutéronome 6:4"], correct: 1, explanation: "Le Psaume 110:1 ('L'Éternel a dit à mon Seigneur : Assieds-toi à ma droite') est le verset de l'AT le plus cité dans le NT — appliqué par Jésus à lui-même (Matthieu 22:44) et utilisé dans les Actes et les épîtres pour proclamer l'exaltation du Christ ressuscité." },
    { question: "Complétez Ésaïe 41:10 : 'Ne crains rien, car je suis avec toi ; ne te laisse pas aller au découragement...' ?", options: ["'...car tu es entre mes mains'", "'...car je suis ton Dieu, je te fortifie, je t'aide, je te soutiens de ma droite triomphante'", "'...car ta foi te sauvera'", "'...car je t'ai choisi avant la fondation du monde'"], correct: 1, explanation: "Isaïe 41:10 : 'Ne crains rien, car je suis avec toi ; ne te laisse pas aller au découragement, car je suis ton Dieu ; je te fortifie, je t'aide, je te soutiens de ma droite triomphante.' L'un des versets de réconfort les plus aimés de l'AT." },
    { question: "Quel verset du Sermon sur la Montagne dit 'Vous êtes le sel de la terre' ?", options: ["Matthieu 5:3", "Matthieu 5:13", "Matthieu 5:20", "Matthieu 6:1"], correct: 1, explanation: "Matthieu 5:13 : 'Vous êtes le sel de la terre. Mais si le sel perd sa saveur, avec quoi la lui rendra-t-on ?' — appel aux disciples à être des agents de conservation et de saveur dans le monde." },
    { question: "Complétez Romains 8:38-39 : 'Car j'ai l'assurance que ni la mort, ni la vie... ne pourront nous séparer de ___' ?", options: ["la grâce de Dieu", "l'amour de Dieu manifesté en Jésus-Christ notre Seigneur", "la paix de Christ", "la joie de l'Esprit Saint"], correct: 1, explanation: "Romains 8:38-39 : '...rien ne pourra nous séparer de l'amour de Dieu manifesté en Jésus-Christ notre Seigneur' — l'une des déclarations les plus puissantes et réconfortantes de la Bible sur la sécurité éternelle du croyant en Christ." },
    { question: "Quel verset de l'Évangile de Jean exprime le cœur de la mission de Christ : 'Car Dieu n'a pas envoyé son Fils dans le monde pour condamner le monde' ?", options: ["Jean 3:17", "Jean 3:18", "Jean 5:24", "Jean 12:47"], correct: 0, explanation: "Jean 3:17 : 'Dieu n'a pas envoyé son Fils dans le monde pour condamner le monde, mais pour que le monde soit sauvé par lui.' Complément essentiel de Jean 3:16 — la mission de Christ est salvatrice, non condamnatrice." },
    { question: "Quel verset biblique décrit la 'nouvelle naissance' comme condition pour voir le Royaume de Dieu ?", options: ["Jean 1:12", "Jean 3:3", "Tite 3:5", "1 Pierre 1:23"], correct: 1, explanation: "Jean 3:3 : 'Jésus lui répondit : En vérité, en vérité, je te le dis, si un homme ne naît de nouveau, il ne peut voir le royaume de Dieu.' — dit à Nicodème, fondement de la doctrine de la régénération." },
    { question: "Complétez Psaume 119:105 : 'Ta parole est une lampe...' ?", options: ["'...pour éclairer ma route'", "'...à mes pieds et une lumière sur mon sentier'", "'...qui guide tous mes pas'", "'...plus précieuse que l'or'"], correct: 1, explanation: "Psaume 119:105 : 'Ta parole est une lampe à mes pieds et une lumière sur mon sentier.' — verset emblématique sur la Parole de Dieu comme guide divin de la vie chrétienne." },
    { question: "Quel verset de l'Apocalypse dit 'Voici, je me tiens à la porte et je frappe' ?", options: ["Apocalypse 3:19", "Apocalypse 3:20", "Apocalypse 22:17", "Apocalypse 21:3"], correct: 1, explanation: "Apocalypse 3:20 : 'Voici, je me tiens à la porte et je frappe. Si quelqu'un entend ma voix et ouvre la porte, j'entrerai chez lui, je souperai avec lui, et lui avec moi.' — dit à l'Église de Laodicée, invitation universelle du Christ." },
    { question: "Complétez 1 Rois 18:21 (Élie sur le Mont Carmel) : 'Jusqu'à quand boiterez-vous des deux côtés ? Si l'Éternel est Dieu...' ?", options: ["'...obéissez à ses commandements'", "'...suivez-le ; et si c'est Baal, suivez-le'", "'...abandonnez vos idoles'", "'...retournez à lui de tout votre cœur'"], correct: 1, explanation: "1 Rois 18:21 : 'Si l'Éternel est Dieu, suivez-le ; et si c'est Baal, suivez-le.' — le défi d'Élie au peuple d'Israël hésitant entre l'Éternel et Baal, appel à un choix radical." },
    { question: "Quel verset dit 'Tout est possible à celui qui croit' ?", options: ["Matthieu 17:20", "Marc 9:23", "Luc 1:37", "Jean 11:40"], correct: 1, explanation: "Marc 9:23 : 'Jésus lui dit : Si tu peux ! Tout est possible à celui qui croit.' — dit au père d'un enfant épileptique qui implorait Jésus pour son fils." },
    { question: "Quel verset dit que 'toutes choses concourent au bien de ceux qui aiment Dieu' ?", options: ["Jérémie 29:11", "Romains 8:28", "Philippiens 4:7", "1 Thessaloniciens 5:18"], correct: 1, explanation: "Romains 8:28 : 'Toutes choses concourent au bien de ceux qui aiment Dieu, de ceux qui sont appelés selon son dessein.' — fondement de la confiance du croyant dans la Providence divine." },
    { question: "Complétez Jean 1:12 : 'Mais à tous ceux qui l'ont reçu...' ?", options: ["'...il leur a accordé la vie éternelle'", "'...il leur a donné le droit de devenir enfants de Dieu'", "'...il les a adoptés comme ses fils bien-aimés'", "'...il les a pardonnés et sanctifiés'"], correct: 1, explanation: "Jean 1:12 : 'Mais à tous ceux qui l'ont reçu, à ceux qui croient en son nom, il leur a donné le droit de devenir enfants de Dieu.' — la réponse johannique à la question du salut : croire = recevoir = devenir enfant de Dieu." },
    { question: "Quel Psaume dit 'L'Éternel est ma lumière et mon salut — de qui aurais-je crainte ?' ?", options: ["Psaume 18", "Psaume 27", "Psaume 46", "Psaume 91"], correct: 1, explanation: "Psaume 27:1 : 'L'Éternel est ma lumière et mon salut — de qui aurais-je crainte ? L'Éternel est le soutien de ma vie — de qui aurais-je peur ?' — chant de confiance absolue en Dieu au milieu de l'adversité." },
    { question: "Quel verset de Paul dit 'Pour moi, vivre c'est Christ, et mourir m'est un gain' ?", options: ["Galates 2:20", "Philippiens 1:21", "Colossiens 3:4", "1 Corinthiens 15:31"], correct: 1, explanation: "Philippiens 1:21 : 'Car pour moi, vivre c'est Christ, et mourir m'est un gain.' — expression parfaite de la vie entièrement centrée sur Christ, au point que la mort elle-même est un gain." },
    { question: "Complétez la promesse de Jean 14:27 : 'Je vous laisse la paix, je vous donne ma paix...' ?", options: ["'...elle surpasse toute intelligence'", "'...je ne vous la donne pas comme le monde la donne. Que votre cœur ne se trouble point et ne s'alarme point'", "'...elle durera jusqu'à la fin des temps'", "'...recevez-la par la prière et la confiance'"], correct: 1, explanation: "Jean 14:27 : '...je ne vous la donne pas comme le monde la donne. Que votre cœur ne se trouble point et ne s'alarme point.' — la paix de Christ, différente de la paix humaine, cadeau d'adieu de Jésus à ses disciples avant la Passion." },
    { question: "Quel verset dit 'Si nous confessons nos péchés, il est fidèle et juste pour nous les pardonner' ?", options: ["1 Jean 2:1", "1 Jean 1:9", "1 Jean 4:10", "Romains 10:9"], correct: 1, explanation: "1 Jean 1:9 : 'Si nous confessons nos péchés, il est fidèle et juste pour nous les pardonner, et pour nous purifier de toute iniquité.' — fondement de la repentance et du pardon dans la vie chrétienne." },
    { question: "Quel verset du livre des Proverbes dit 'La crainte de l'Éternel est le commencement de la sagesse' ?", options: ["Proverbes 1:7", "Proverbes 3:5", "Proverbes 9:10", "Psaume 111:10"], correct: 0, explanation: "Proverbes 1:7 : 'La crainte de l'Éternel est le commencement de la science (sagesse) ; les insensés méprisent la sagesse et l'instruction.' — verset programmatique du livre de la Sagesse." },
    { question: "Quel verset dit 'Je suis la résurrection et la vie' ?", options: ["Jean 6:40", "Jean 11:25", "Jean 14:19", "Jean 20:31"], correct: 1, explanation: "Jean 11:25 : 'Je suis la résurrection et la vie. Celui qui croit en moi vivra, quand même il serait mort' — dit à Marthe avant la résurrection de Lazare." },
    { question: "Complétez Ésaïe 40:31 : 'Mais ceux qui se confient en l'Éternel renouvellent leur force...' ?", options: ["'...ils marchent et ne se lassent point'", "'...ils prennent le vol comme des aigles ; ils courent et ne se lassent point, ils marchent et ne se fatiguent pas'", "'...ils trouvent le repos dans leurs âmes'", "'...leur espérance ne sera jamais déçue'"], correct: 1, explanation: "Ésaïe 40:31 : '...ils prennent le vol comme des aigles ; ils courent et ne se lassent point, ils marchent et ne se fatiguent pas.' — promesse de renouvellement divin pour ceux qui attendent l'Éternel dans la confiance." },
    { question: "Quel verset du NT dit que 'la foi vient de ce qu'on entend' ?", options: ["Hébreux 11:1", "Romains 10:17", "1 Pierre 1:25", "Galates 3:2"], correct: 1, explanation: "Romains 10:17 : 'Ainsi la foi vient de ce qu'on entend, et ce qu'on entend vient de la parole de Christ.' — fondement de l'importance de la prédication et de la proclamation de l'Évangile pour éveiller la foi." },
    { question: "Quel est le verset de l'AT qui dit 'L'Éternel est proche de ceux qui ont le cœur brisé' ?", options: ["Psaume 34:19", "Psaume 51:17", "Psaume 147:3", "Esaïe 57:15"], correct: 0, explanation: "Psaume 34:19 : 'L'Éternel est proche de ceux qui ont le cœur brisé, et il sauve ceux qui ont l'esprit dans l'abattement.' — verset de réconfort profond pour les blessés de la vie." },
    { question: "Complétez 2 Timothée 3:16 : 'Toute écriture est inspirée de Dieu...' ?", options: ["'...et est la vérité absolue'", "'...et utile pour enseigner, pour convaincre, pour corriger, pour instruire dans la justice'", "'...et ne doit jamais être questionnée'", "'...et a été donnée aux apôtres seuls'"], correct: 1, explanation: "2 Timothée 3:16 : 'Toute écriture est inspirée de Dieu, et utile pour enseigner, pour convaincre, pour corriger, pour instruire dans la justice.' — verset fondateur de la doctrine de l'inspiration biblique." },
    { question: "Quel verset du Sermon sur la Montagne dit 'Bienheureux les miséricordieux' ?", options: ["Matthieu 5:3", "Matthieu 5:7", "Matthieu 5:9", "Matthieu 5:12"], correct: 1, explanation: "Matthieu 5:7 : 'Bienheureux les miséricordieux, car ils obtiendront miséricorde.' — la 5e Béatitude du Sermon sur la Montagne." },
    { question: "Quel verset de l'Épître aux Hébreux dit que la Parole de Dieu est 'plus vive et plus efficace qu'une épée à deux tranchants' ?", options: ["Hébreux 1:3", "Hébreux 4:12", "Hébreux 6:19", "Hébreux 12:1"], correct: 1, explanation: "Hébreux 4:12 : 'Car la parole de Dieu est vivante et efficace, plus tranchante qu'une épée quelconque à deux tranchants, pénétrante jusqu'à partager l'âme et l'esprit...'" },
    { question: "Complétez Matthieu 11:28 : 'Venez à moi, vous tous qui êtes fatigués...' ?", options: ["'...et je vous guérirai'", "'...et chargés, et je vous donnerai du repos'", "'...et je vous enseignerai la vérité'", "'...et je vous délivrerai de vos péchés'"], correct: 1, explanation: "Matthieu 11:28 : 'Venez à moi, vous tous qui êtes fatigués et chargés, et je vous donnerai du repos.' — invitation universelle de Jésus à tous ceux qui portent des fardeaux." },
    { question: "Quel est le verset de 1 Corinthiens 13 qui dit que 'l'amour ne périt jamais' ?", options: ["1 Corinthiens 13:4", "1 Corinthiens 13:8", "1 Corinthiens 13:12", "1 Corinthiens 13:13"], correct: 1, explanation: "1 Corinthiens 13:8 : 'L'amour ne périt jamais. Les prophéties prendront fin, les langues cesseront, la connaissance disparaîtra.' — la permanence de l'agapè au-delà de tous les dons spirituels." },
    { question: "Quel verset dit 'Demandez et l'on vous donnera ; cherchez et vous trouverez ; frappez et l'on vous ouvrira' ?", options: ["Matthieu 6:6", "Matthieu 7:7", "Luc 11:9", "Les deux : Matthieu 7:7 et Luc 11:9"], correct: 3, explanation: "Ce verset célèbre sur la prière persévérante se trouve dans Matthieu 7:7 (Sermon sur la Montagne) et Luc 11:9 (dans le contexte de l'enseignement sur la prière après le Notre Père)." },
    { question: "Quel verset résume la Loi et les Prophètes selon Jésus : 'Tout ce que vous voulez que les hommes fassent pour vous...' ?", options: ["Matthieu 5:48", "Matthieu 7:12", "Luc 6:31", "Les deux : Matthieu 7:12 et Luc 6:31"], correct: 3, explanation: "La 'règle d'or' — 'Tout ce que vous voulez que les hommes fassent pour vous, faites-le de même pour eux' — est dans Matthieu 7:12 (avec l'addition 'car c'est la loi et les prophètes') et Luc 6:31. Jésus la présente comme le résumé de toute la révélation morale." }
  ],
  intermediaire: [
    { question: "'En toutes choses, Dieu travaille pour le bien...' — Quelle référence exacte ?", options: ["Philippiens 4:13", "Romains 8:28", "Jérémie 29:11", "Proverbes 3:5"], correct: 1, explanation: "Romains 8:28 : 'Toutes choses concourent au bien de ceux qui aiment Dieu.'" },
    { question: "Qui a dit 'Ce n'est plus moi qui vis, c'est Christ qui vit en moi' ?", options: ["Pierre", "Jean", "Paul", "Jacques"], correct: 2, explanation: "Paul écrit cela dans Galates 2:20 pour exprimer l'union avec Christ." },
    { question: "Quel psaume commence par 'Les cieux racontent la gloire de Dieu' ?", options: ["Psaume 8", "Psaume 19", "Psaume 33", "Psaume 148"], correct: 1, explanation: "Le Psaume 19:2 : 'Les cieux racontent la gloire de Dieu, et l'étendue manifeste l'œuvre de ses mains.'" },
    { question: "Dans quel verset Paul demande-t-il aux croyants de 'revêtir l'armure de Dieu' ?", options: ["Romains 13:12", "Éphésiens 6:11", "2 Corinthiens 10:4", "1 Thessaloniciens 5:8"], correct: 1, explanation: "Éphésiens 6:11 : 'Revêtez-vous de toutes les armes de Dieu, afin de pouvoir tenir ferme contre les ruses du diable.'" },
    { question: "Quel verset de Jean dit 'Moi et le Père nous sommes un' ?", options: ["Jean 1:1", "Jean 8:58", "Jean 10:30", "Jean 17:21"], correct: 2, explanation: "Jean 10:30 : 'Moi et le Père nous sommes un.'" },
    { question: "Complétez Proverbes 22:6 : 'Instruis l'enfant selon...' ?", options: ["...les préceptes de Dieu", "...la voie qu'il doit suivre; et quand il sera vieux, il ne s'en détournera pas", "...la sagesse du Seigneur", "...les commandements"], correct: 1, explanation: "Proverbes 22:6 : 'Instruis l'enfant selon la voie qu'il doit suivre; et quand il sera vieux, il ne s'en détournera pas.'" },
    { question: "'Cherchez d'abord le royaume et la justice de Dieu...' — Quel livre ?", options: ["Luc 12", "Matthieu 6", "Jean 15", "Romains 14"], correct: 1, explanation: "Cette parole de Jésus se trouve dans le Sermon sur la Montagne, Matthieu 6:33." },
    { question: "Quel verset dit 'Toute écriture est inspirée de Dieu, et utile pour enseigner...' ?", options: ["1 Pierre 1:23", "2 Timothée 3:16", "Hébreux 4:12", "Jean 17:17"], correct: 1, explanation: "2 Timothée 3:16 affirme l'inspiration divine des Écritures." },
    { question: "Dans Matthieu 5, que dit Jésus sur les 'artisans de paix' ?", options: ["Ils hériteront la terre", "Ils seront consolés", "Ils seront appelés fils de Dieu", "Ils verront Dieu"], correct: 2, explanation: "Matthieu 5:9 : 'Heureux les artisans de paix, car ils seront appelés fils de Dieu!'" },
    { question: "Quel verset du livre de Michée résume la vocation du croyant en trois éléments ?", options: ["Michée 5:2", "Michée 6:8", "Michée 7:7", "Michée 4:3"], correct: 1, explanation: "Michée 6:8 : 'pratiquer la justice, aimer la miséricorde, et marcher humblement avec ton Dieu.'" },
    { question: "Complétez Romains 12:2 : 'Ne vous conformez pas au siècle présent, mais soyez transformés...' ?", options: ["...par la puissance de l'Esprit", "...par le renouvellement de l'intelligence", "...par la lecture de la Parole", "...par la prière et le jeûne"], correct: 1, explanation: "Romains 12:2 : '...soyez transformés par le renouvellement de l'intelligence.'" },
    { question: "Quel verset dit 'Il n'y a donc maintenant aucune condamnation pour ceux qui sont en Jésus-Christ' ?", options: ["Jean 3:17", "Romains 8:1", "Éphésiens 1:7", "Colossiens 2:14"], correct: 1, explanation: "Romains 8:1 : 'Il n'y a donc maintenant aucune condamnation pour ceux qui sont en Jésus-Christ.'" },
    { question: "Quel verset de l'Ancien Testament est cité comme fondement de la justification par la foi dans Romains 1:17 ?", options: ["Genèse 15:6", "Habacuc 2:4", "Ésaïe 53:11", "Psaume 32:1"], correct: 1, explanation: "Romains 1:17 cite Habacuc 2:4 : 'Le juste vivra par la foi.'" },
    { question: "Complétez 1 Corinthiens 13:13 : 'Maintenant donc ces trois choses demeurent...' ?", options: ["...la plus grande c'est la foi", "...mais la plus grande c'est l'amour", "...toutes les trois sont égales", "...la plus grande c'est l'espérance"], correct: 1, explanation: "1 Corinthiens 13:13 : '...mais la plus grande c'est l'amour.'" },
    { question: "Quel psaume contient le cri 'Mon Dieu, mon Dieu, pourquoi m'as-tu abandonné ?' que Jésus cite sur la croix ?", options: ["Psaume 18", "Psaume 22", "Psaume 31", "Psaume 69"], correct: 1, explanation: "Le Psaume 22:1 commence par ce cri que Jésus cite en Matthieu 27:46 et Marc 15:34." },
    { question: "Quel verset dit 'L'Éternel, l'Éternel, Dieu miséricordieux et compatissant, lent à la colère, riche en grâce et en fidélité' ?", options: ["Exode 34:6", "Nombres 14:18", "Psaume 86:15", "Tous ces passages"], correct: 3, explanation: "L'auto-révélation divine d'Exode 34:6-7 (les '13 attributs divins') est reprise mot pour mot dans Nombres 14:18, Psaume 86:15 et de nombreux autres textes — c'est la définition centrale du caractère de Dieu dans l'AT." },
    { question: "Complétez Galates 2:20 : 'J'ai été crucifié avec Christ ; et si je vis...' ?", options: ["'...c'est par la grâce de Dieu'", "'...ce n'est plus moi qui vis, c'est Christ qui vit en moi'", "'...c'est par la puissance de l'Esprit'", "'...c'est que ma foi est grande'"], correct: 1, explanation: "Galates 2:20 : 'J'ai été crucifié avec Christ ; et si je vis, ce n'est plus moi qui vis, c'est Christ qui vit en moi ; et si je vis maintenant dans la chair, je vis dans la foi au Fils de Dieu...' — le mystère de la vie en Christ." },
    { question: "Quel verset de l'Évangile de Jean dit 'La vérité vous affranchira' ?", options: ["Jean 8:31", "Jean 8:32", "Jean 8:36", "Jean 17:17"], correct: 1, explanation: "Jean 8:32 : 'Vous connaîtrez la vérité, et la vérité vous affranchira.' — dit par Jésus à ceux qui demeurent dans sa parole. La 'vérité' ici est christologique (Jean 14:6 : 'Je suis... la vérité')." },
    { question: "Quel verset de Matthieu 28 constitue la 'Grande Commission' dans son intégralité ?", options: ["Matthieu 28:18", "Matthieu 28:19", "Matthieu 28:18-20 : triple mandat (autorité, mission, présence)", "Matthieu 28:20"], correct: 2, explanation: "La Grande Commission (Matthieu 28:18-20) est un triplé : (1) fondement — 'Tout pouvoir m'a été donné' ; (2) mandat — 'Allez, faites de toutes les nations des disciples, les baptisant et leur enseignant' ; (3) promesse — 'Et voici, je suis avec vous tous les jours.'" },
    { question: "Quel verset d'Ézéchiel annonce la promesse d'un 'cœur nouveau et d'un esprit nouveau' ?", options: ["Ézéchiel 11:19", "Ézéchiel 36:26", "Ézéchiel 37:14", "Tous ces versets"], correct: 3, explanation: "La promesse du cœur nouveau apparaît en Ézéchiel 11:19, 18:31 et surtout 36:26 : 'Je vous donnerai un cœur nouveau et je mettrai en vous un esprit nouveau ; j'ôterai de votre corps le cœur de pierre et je vous donnerai un cœur de chair.' — accomplissement dans la nouvelle naissance (Jean 3:3-5)." },
    { question: "Complétez Hébreux 12:1-2 : '...courons avec persévérance dans la carrière qui nous est ouverte, les regards fixés sur...' ?", options: ["'...Dieu notre Père et créateur'", "'...Jésus, le chef et le consommateur de la foi'", "'...la gloire qui nous attend au ciel'", "'...la nuée de témoins qui nous entourent'"], correct: 1, explanation: "Hébreux 12:1-2 : '...courons avec persévérance dans la carrière qui nous est ouverte, les regards fixés sur Jésus, le chef et le consommateur de la foi.' — appel à fixer notre regard sur Christ seul, encouragé par la 'nuée de témoins' de Hébreux 11." },
    { question: "Quel est le verset d'Isaïe 53 qui dit 'Il était blessé pour nos péchés' ?", options: ["Ésaïe 53:3", "Ésaïe 53:5", "Ésaïe 53:6", "Ésaïe 53:11"], correct: 1, explanation: "Ésaïe 53:5 : 'Mais il était blessé pour nos péchés, brisé pour nos iniquités ; le châtiment qui nous donne la paix est tombé sur lui, et c'est par ses meurtrissures que nous sommes guéris.' — le verset christologique capital de l'AT." },
    { question: "Quel verset de l'Apocalypse dit 'Dieu lui-même sera avec eux. Il essuiera toute larme de leurs yeux' ?", options: ["Apocalypse 7:17", "Apocalypse 21:3-4", "Apocalypse 22:3", "Apocalypse 21:7"], correct: 1, explanation: "Apocalypse 21:3-4 : 'Dieu lui-même sera avec eux... Il essuiera toute larme de leurs yeux, la mort ne sera plus, et il n'y aura plus ni deuil, ni cri, ni douleur, car les premières choses ont disparu.' — vision eschatologique de la restauration totale." },
    { question: "Quel verset de Jean 3 dit 'Il faut que vous naissiez de nouveau' ?", options: ["Jean 3:3", "Jean 3:5", "Jean 3:7", "Jean 3:16"], correct: 2, explanation: "Jean 3:7 : 'Ne t'étonne pas que je t'aie dit : Il faut que vous naissiez de nouveau.' — Jésus insiste auprès de Nicodème sur la nécessité absolue de la nouvelle naissance spirituelle." },
    { question: "Quel verset de Proverbes dit 'L'homme propose et Dieu dispose' (dans son équivalent biblique) ?", options: ["Proverbes 16:1", "Proverbes 16:9", "Proverbes 19:21", "Proverbes 21:31"], correct: 1, explanation: "Proverbes 16:9 : 'Le cœur de l'homme médite sa voie, mais c'est l'Éternel qui dirige ses pas.' — l'équivalent biblique du proverbe 'l'homme propose, Dieu dispose'." },
    { question: "Complétez 2 Corinthiens 12:9 : 'Ma grâce te suffit, car ma puissance s'accomplit dans la faiblesse...' ?", options: ["'...c'est pourquoi je me glorifierai bien plus volontiers dans mes faiblesses'", "'...ne crains donc pas ta faiblesse'", "'...et ma joie sera parfaite dans ton service'", "'...souviens-toi de mes commandements'"], correct: 0, explanation: "2 Corinthiens 12:9 : 'Ma grâce te suffit, car ma puissance s'accomplit dans la faiblesse. Je me glorifierai donc bien plus volontiers dans mes faiblesses, afin que la puissance de Christ repose sur moi.' — réponse de Dieu à Paul suppliant d'enlever l'écharde dans sa chair — paradoxe central de la théologie paulinienne." },
    { question: "Quel verset dit 'L'Éternel est mon rocher, ma forteresse et mon libérateur' ?", options: ["Psaume 18:2", "Psaume 62:2", "Psaume 91:2", "2 Samuel 22:2"], correct: 0, explanation: "Psaume 18:2 : 'L'Éternel est mon rocher, ma forteresse et mon libérateur ; mon Dieu est mon rocher où je me réfugie, mon bouclier et la force qui me sauve, ma haute retraite.' — David chante sa délivrance par Dieu après ses ennemis." },
    { question: "Quel verset de l'Évangile dit 'La moisson est grande, mais les ouvriers sont peu nombreux' ?", options: ["Matthieu 9:37-38", "Luc 10:2", "Jean 4:35", "Les deux premiers : Matthieu 9:37-38 et Luc 10:2"], correct: 3, explanation: "Ce verset missionnaire de Jésus ('La moisson est grande mais les ouvriers sont peu nombreux. Priez donc le Seigneur de la moisson d'envoyer des ouvriers dans sa moisson') se retrouve dans Matthieu 9:37-38 et Luc 10:2 dans deux contextes différents." },
    { question: "Quel verset de l'Épître aux Romains dit 'Ne soyez redevables à personne, sinon de l'amour mutuel' ?", options: ["Romains 12:9", "Romains 13:8", "Romains 15:1", "Galates 6:2"], correct: 1, explanation: "Romains 13:8 : 'Ne soyez redevables à personne, si ce n'est de vous aimer les uns les autres ; car celui qui aime les autres a accompli la loi.' — Paul relie la liberté financière et l'amour chrétien comme accomplissement de toute la Loi." },
    { question: "Quel verset annonce le Serviteur Souffrant en disant 'Il a porté nos douleurs et chargé de nos souffrances' ?", options: ["Ésaïe 53:3", "Ésaïe 53:4", "Ésaïe 53:7", "Ésaïe 53:10"], correct: 1, explanation: "Ésaïe 53:4 : 'Cependant, ce sont nos souffrances qu'il a portées, c'est de nos douleurs qu'il s'est chargé ; et nous l'avons considéré comme puni, frappé de Dieu, et humilié.' — cité dans Matthieu 8:17 pour les guérisons de Jésus." },
    { question: "Quel verset de Jean dit 'Si vous demeurez dans ma Parole, vous êtes vraiment mes disciples' ?", options: ["Jean 8:31", "Jean 15:7", "Jean 17:17", "Jean 14:23"], correct: 0, explanation: "Jean 8:31 : 'Jésus dit aux Juifs qui avaient cru en lui : Si vous demeurez dans ma parole, vous êtes vraiment mes disciples.' — la persévérance dans la Parole comme critère du vrai discipulat selon Jean." },
    { question: "Quel verset dit que 'celui qui veut sauver sa vie la perdra, mais celui qui perdra sa vie à cause de moi la trouvera' ?", options: ["Matthieu 10:39", "Matthieu 16:25", "Luc 9:24", "Les trois se retrouvent dans les 3 évangiles synoptiques"], correct: 3, explanation: "Ce paradoxe sur la vie et la mort — 'perdre sa vie pour la trouver' — apparaît dans Matthieu 10:39 ; 16:25, Marc 8:35, Luc 9:24 et 17:33 ; et même Jean 12:25 — probablement dit plusieurs fois par Jésus tant c'est central à son enseignement sur le discipulat." },
    { question: "Complétez la prophétie de Joël 2:28 citée par Pierre à la Pentecôte : 'Dans les derniers jours... vos fils et vos filles prophétiseront...' ?", options: ["'...et les vieillards auront des visions'", "'...et vos vieillards auront des songes ; et vos jeunes gens verront des visions'", "'...et l'Esprit de Dieu descendra sur tous les hommes'", "'...et toute la terre connaîtra l'Éternel'"], correct: 1, explanation: "Joël 2:28 (3:1 en hébreu) / Actes 2:17 : 'Dans les derniers jours... vos fils et vos filles prophétiseront, vos vieillards auront des songes, et vos jeunes gens verront des visions.' — Pierre cite Joël pour expliquer la Pentecôte comme accomplissement de la promesse de l'effusion de l'Esprit sur toute chair." },
    { question: "Quel verset de l'AT sur la foi est cité trois fois dans le NT (Romains 1:17 ; Galates 3:11 ; Hébreux 10:38) ?", options: ["Genèse 15:6", "Habacuc 2:4", "Ésaïe 7:9", "Deutéronome 6:5"], correct: 1, explanation: "Habacuc 2:4 : 'Le juste vivra par sa foi' — ce verset bref et explosif est cité 3 fois dans le NT, marquant la centralité de la foi pour chaque aspect de la vie chrétienne (justification chez Paul, marche quotidienne chez Paul, persévérance chez l'auteur des Hébreux)." },
    { question: "Quel verset de l'Épître aux Éphésiens dit 'Il n'y a pas de lutte contre la chair et le sang, mais contre...' ?", options: ["Éphésiens 6:10", "Éphésiens 6:12", "Éphésiens 6:17", "Éphésiens 6:18"], correct: 1, explanation: "Éphésiens 6:12 : '...contre les principautés, contre les pouvoirs, contre les princes des ténèbres de ce siècle, contre les esprits méchants dans les lieux célestes.' — Paul révèle la dimension spirituelle invisible de la guerre chrétienne." },
    { question: "Complétez Jean 15:13 : 'Il n'y a pas de plus grand amour que de...' ?", options: ["'...aimer ceux qui nous haïssent'", "'...donner sa vie pour ses amis'", "'...aimer Dieu de tout son cœur'", "'...pardonner à ceux qui nous offensent'"], correct: 1, explanation: "Jean 15:13 : 'Il n'y a pas de plus grand amour que de donner sa vie pour ses amis.' — Jésus annonce son sacrifice comme expression suprême de l'agapè, dans le discours de la vigne (Jean 15)." },
    { question: "Quel verset du Psaume 51 montre la repentance profonde de David après son péché ?", options: ["Psaume 51:1", "Psaume 51:4", "Psaume 51:10", "Psaume 51:17"], correct: 3, explanation: "Psaume 51:17 : 'Les sacrifices qui sont agréables à Dieu, c'est un esprit brisé ; ô Dieu, tu ne dédaignes pas un cœur brisé et contrit.' — après l'affaire de Bath-Schéba, David comprend que la vraie repentance surpasse tout sacrifice extérieur." },
    { question: "Quel verset de Colossiens dit 'Vous êtes morts, et votre vie est cachée avec Christ en Dieu' ?", options: ["Colossiens 2:12", "Colossiens 3:3", "Colossiens 3:11", "Colossiens 1:27"], correct: 1, explanation: "Colossiens 3:3 : 'Car vous êtes morts, et votre vie est cachée avec Christ en Dieu.' — le mystère de l'union avec Christ : le croyant est mort avec Christ (au vieux moi) et sa vraie vie est désormais 'cachée en Dieu' — révélée à la Parousie (Colossiens 3:4)." },
    { question: "Quel verset du NT résume la mission de Jésus : 'Le Fils de l'homme est venu chercher et sauver ce qui était perdu' ?", options: ["Matthieu 18:11", "Luc 19:10", "Jean 3:17", "1 Timothée 1:15"], correct: 1, explanation: "Luc 19:10 : 'Car le Fils de l'homme est venu chercher et sauver ce qui était perdu.' — dit par Jésus à la maison de Zachée, résumant en une phrase toute sa mission sotériologique." },
    { question: "Quel verset de Génèse contient la première promesse messianique biblique (Protévangile) ?", options: ["Genèse 3:15", "Genèse 12:3", "Genèse 22:18", "Genèse 49:10"], correct: 0, explanation: "Genèse 3:15 : 'Je mettrai une hostilité entre toi et la femme, entre ta postérité et sa postérité : celle-ci t'écrasera la tête, et tu lui blesseras le talon.' — le 'Protévangile' ('première bonne nouvelle'), première annonce messianique après la Chute." },
    { question: "Quel verset de Deutéronome 6:4-5 est appelé le 'Shema Israël' ?", options: ["'Écoute, Israël : l'Éternel est notre Dieu, l'Éternel est un. Tu aimeras l'Éternel de tout ton cœur'", "'Tu n'auras pas d'autres dieux devant ma face'", "'Tu aimeras ton prochain comme toi-même'", "'L'Éternel ton Dieu est Dieu des dieux et Seigneur des seigneurs'"], correct: 0, explanation: "Deutéronome 6:4-5 : 'Écoute, Israël : l'Éternel est notre Dieu, l'Éternel est un. Tu aimeras l'Éternel ton Dieu de tout ton cœur, de toute ton âme et de toute ta force.' — la prière centrale du judaïsme, citée par Jésus comme le premier commandement (Marc 12:29-30)." },
    { question: "Quel verset dit 'Approchez-vous de Dieu, et il s'approchera de vous' ?", options: ["Hébreux 10:22", "Jacques 4:8", "1 Jean 4:19", "Psaume 145:18"], correct: 1, explanation: "Jacques 4:8 : 'Approchez-vous de Dieu, et il s'approchera de vous. Purifiez vos mains, pécheurs ; sanctifiez vos cœurs, vous qui avez l'âme partagée.' — appel à la repentance et à la sanctification comme conditions de l'intimité avec Dieu." },
    { question: "Quel verset de Sophonie annonce 'L'Éternel ton Dieu est au milieu de toi, comme un puissant sauveur' ?", options: ["Sophonie 1:7", "Sophonie 3:17", "Sophonie 2:3", "Michée 7:18"], correct: 1, explanation: "Sophonie 3:17 : 'L'Éternel ton Dieu est au milieu de toi, comme un puissant sauveur ; il aura en toi une joie et une allégresse ; il se taira dans son amour, il poussera des cris de joie sur toi.' — Dieu qui chante de joie sur son peuple, l'un des versets les plus touchants de l'AT." },
    { question: "Quel verset de Romains dit 'Car tous ont péché et sont privés de la gloire de Dieu' ?", options: ["Romains 1:18", "Romains 3:23", "Romains 5:12", "Romains 6:23"], correct: 1, explanation: "Romains 3:23 : 'Car tous ont péché et sont privés de la gloire de Dieu.' — avec Romains 3:24-25, ce verset résume le diagnostic universel (tous ont péché) et le remède divin (justification gratuite par le rachat en Christ)." },
    { question: "Complétez Philippiens 4:7 : 'Et la paix de Dieu, qui surpasse toute intelligence...' ?", options: ["'...sera avec vous pour toujours'", "'...gardera vos cœurs et vos pensées en Jésus-Christ'", "'...descendra sur vous comme une rivière'", "'...vous donnera force et courage'"], correct: 1, explanation: "Philippiens 4:7 : '...gardera vos cœurs et vos pensées en Jésus-Christ.' — promesse de la paix divine qui 'surpasse toute intelligence', accordée à ceux qui présentent leurs requêtes à Dieu 'avec actions de grâces' (Philippiens 4:6)." },
    { question: "Quel verset de l'Évangile de Luc dit que 'à celui à qui on a beaucoup donné, on demandera beaucoup' ?", options: ["Luc 12:47", "Luc 12:48", "Luc 19:26", "Matthieu 25:29"], correct: 1, explanation: "Luc 12:48 : '...mais à celui à qui on a beaucoup donné, on demandera beaucoup, et à celui à qui on a beaucoup confié, on demandera davantage.' — principe de responsabilité proportionnelle dans le Royaume de Dieu." },
    { question: "Quel verset dit 'Le Seigneur n'est pas en retard pour l'accomplissement de sa promesse... mais il use de patience envers vous' ?", options: ["2 Pierre 3:8", "2 Pierre 3:9", "Hébreux 10:37", "Apocalypse 22:20"], correct: 1, explanation: "2 Pierre 3:9 : 'Le Seigneur ne tarde pas dans l'accomplissement de sa promesse... mais il use de patience envers vous, ne voulant pas qu'aucun périsse, mais voulant que tous arrivent à la repentance.' — réponse à ceux qui questionnent le délai de la Parousie." },
    { question: "Quel verset résume la loi de la semence et de la récolte spirituelle ?", options: ["Galates 6:7", "Galates 6:8", "2 Corinthiens 9:6", "Les deux : Galates 6:7-8 et 2 Corinthiens 9:6"], correct: 3, explanation: "Galates 6:7-8 ('Dieu ne se laisse pas moquer. Ce qu'un homme sème, il le moissonnera aussi') et 2 Corinthiens 9:6 ('Celui qui sème peu moissonnera peu, et celui qui sème abondamment moissonnera abondamment') — deux expressions différentes du même principe de la sémence et de la récolte spirituelle." },
    { question: "Quel verset dit 'Fortifiez-vous dans le Seigneur et dans la puissance de sa force' ?", options: ["Éphésiens 6:10", "2 Timothée 2:1", "1 Corinthiens 16:13", "Philippiens 4:13"], correct: 0, explanation: "Éphésiens 6:10 : 'Au reste, fortifiez-vous dans le Seigneur et dans la puissance de sa force.' — exhortation d'introduction à la section sur l'armure de Dieu (Éphésiens 6:10-18), soulignant que la force chrétienne vient de Dieu, non de nous." },
    { question: "Quel verset de Néhémie dit 'La joie de l'Éternel est votre force' ?", options: ["Néhémie 8:8", "Néhémie 8:10", "Néhémie 9:17", "Esdras 3:11"], correct: 1, explanation: "Néhémie 8:10 : '...ne soyez pas en deuil, car la joie de l'Éternel sera votre force.' — dit lors de la célébration publique de la lecture de la Loi retrouvée, alors que le peuple pleurait d'émotion." },
    { question: "Complétez Apocalypse 22:20 : 'Oui, je viens bientôt. Amen ! Viens...' ?", options: ["'...Seigneur Jésus ! La grâce du Seigneur Jésus soit avec tous.'", "'...Seigneur, dans ta gloire céleste'", "'...et établis ton royaume éternel'", "'...et accomplis tes promesses fidèles'"], correct: 0, explanation: "Apocalypse 22:20-21 : 'Oui, je viens bientôt. Amen ! Viens, Seigneur Jésus ! Que la grâce du Seigneur Jésus soit avec tous !' — les derniers mots de la Bible : espérance eschatologique (Maranatha) + bénédiction de grâce." },
    { question: "Quel verset dit 'Voici, je vous donne le pouvoir de marcher sur les serpents et les scorpions... et rien ne pourra vous nuire' ?", options: ["Marc 16:18", "Luc 10:19", "Jean 14:12", "Actes 1:8"], correct: 1, explanation: "Luc 10:19 : 'Voici, je vous ai donné le pouvoir de marcher sur les serpents et les scorpions, et sur toute la puissance de l'ennemi ; et rien ne pourra vous nuire.' — dit par Jésus aux 72 disciples revenus joyeux de leur mission." },
    { question: "Quel verset de l'Épître de Jacques dit que 'la prière fervente du juste a une grande efficacité' ?", options: ["Jacques 1:5", "Jacques 4:3", "Jacques 5:16", "Jacques 5:17"], correct: 2, explanation: "Jacques 5:16 : 'Avouez donc vos péchés les uns aux autres, et priez les uns pour les autres, afin que vous soyez guéris. La prière fervente du juste a une grande efficacité.' — fondement de la prière d'intercession dans l'Église." },
    { question: "Quel verset de l'Apocalypse dit 'Ils l'ont vaincu à cause du sang de l'Agneau et à cause de la parole de leur témoignage' ?", options: ["Apocalypse 7:14", "Apocalypse 12:11", "Apocalypse 15:2", "Apocalypse 17:14"], correct: 1, explanation: "Apocalypse 12:11 : 'Ils l'ont vaincu à cause du sang de l'Agneau et à cause de la parole de leur témoignage, et ils n'ont pas aimé leur vie jusqu'à craindre la mort.' — les deux armes du chrétien victorieux : le sang du Christ et le témoignage fidèle." },
    { question: "Quel verset de l'Évangile de Luc exprime la miséricorde de Dieu dans la parabole du père prodigue ?", options: ["Luc 15:20", "Luc 15:22", "Luc 15:24", "Luc 15:32"], correct: 0, explanation: "Luc 15:20 : '...il était encore loin, que son père le vit et fut ému de compassion, il courut se jeter à son cou et le baisa.' — le cœur de la parabole : le père qui court vers le fils repentant, image incomparable de la grâce divine accueillant le pécheur qui revient." }
  ],
  expert: [
    { question: "Dans quel verset le terme hébreu 'chesed' apparaît-il dans la révélation divine à Moïse ?", options: ["Genèse 32:10", "Exode 34:6-7", "Deutéronome 7:9", "Toutes ces références"], correct: 3, explanation: "'Chesed' (חֶסֶד) est un terme central décrivant la fidélité aimante de Dieu, présent dans toutes ces références." },
    { question: "Quel terme hébreu signifie à la fois 'vérité', 'fidélité' et 'solidité' ?", options: ["Shalom", "Emeth", "Kodesh", "Hesed"], correct: 1, explanation: "'Emeth' (אֱמֶת) signifie 'vérité, fidélité, solidité', reflétant le caractère inébranlable de Dieu." },
    { question: "Quel est le contexte original de Jérémie 29:11 souvent mal interprété ?", options: ["Une promesse faite à Jérémie personnellement", "Une lettre aux exilés de Babylone pour une nation entière après 70 ans", "Un oracle pour les rois d'Israël", "Une promesse eschatologique"], correct: 1, explanation: "Jérémie 29:11 est adressé à la nation israélite en exil à Babylone — pas une promesse individuelle immédiate." },
    { question: "Dans Ésaïe 53:5, quel terme hébreu traduit par 'transpercé' a une connotation sacrificielle profonde ?", options: ["Nakah", "Chalal", "Makat", "Pasha"], correct: 1, explanation: "'Chalal' (חָלַל) signifie 'transpercé mortellement', avec une connotation de mort violente et sacrificielle." },
    { question: "Quelle est la structure rhétorique du prologue de Jean (1:1-18) ?", options: ["Une introduction narrative simple", "Un hymne christologique en forme de chiasme", "Une argumentation philosophique grecque", "Un discours prophétique en strophes"], correct: 1, explanation: "Le prologue de Jean est structuré en chiasme avec le Logos comme centre." },
    { question: "Dans Apocalypse 1:8, quel terme grec complète 'Je suis l'Alpha et l'Oméga' ?", options: ["Pantokrator (Tout-Puissant)", "Kyrios (Seigneur)", "Christos (Christ)", "Theos (Dieu)"], correct: 0, explanation: "Apocalypse 1:8 : '...le Tout-Puissant (Pantokrator)'." },
    { question: "Quel est le sens théologique du 'sang de l'aspersion' dans Hébreux 12:24 ?", options: ["Le baptême chrétien", "La purification des péchés par l'intercession du Christ ressuscité", "Le sacrifice de la Pâque", "Le rite de consécration des prêtres"], correct: 1, explanation: "Le 'sang de l'aspersion' fait référence au sang du Christ qui 'parle mieux' que celui d'Abel." },
    { question: "Quelle citation d'Habacuc 2:4 est reprise trois fois dans le NT ?", options: ["'L'Éternel est dans son saint temple'", "'Le juste vivra par la foi'", "'Car encore un peu de temps, et celui qui doit venir viendra'", "'Malheur à celui qui dit au bois: éveille-toi!'"], correct: 1, explanation: "'Le juste vivra par la foi' (Habacuc 2:4) est cité dans Romains 1:17, Galates 3:11 et Hébreux 10:38." },
    { question: "Quel terme grec du NT, à la racine du mot 'Église', implique une 'séparation' ?", options: ["Hagios (saint)", "Ekklesia (appelés hors de)", "Pneuma (esprit)", "Doxa (gloire)"], correct: 1, explanation: "'Ekklesia' signifie littéralement 'ceux qui sont appelés hors de'." },
    { question: "Dans Matthieu 5:17, comment Jésus complète-t-il 'Je ne suis pas venu abolir...' ?", options: ["...les traditions des anciens", "...la Loi ni les Prophètes; je suis venu non pour abolir, mais pour accomplir", "...les commandements, mais les approfondir", "...les sacrifices, mais les remplacer par la grâce"], correct: 1, explanation: "Matthieu 5:17 : 'je suis venu non pour abolir, mais pour accomplir.'" },
    { question: "Quel est le contexte liturgique original du 'Notre Père' dans Matthieu 6 ?", options: ["Une prière pour les repas", "Une instruction sur la prière authentique par opposition à la prière ostentatoire", "Une liturgie pour le sabbat", "Un discours eschatologique"], correct: 1, explanation: "Le 'Notre Père' s'inscrit dans l'enseignement de Jésus sur la prière par contraste avec la prière hypocrite (Matthieu 6:5-8)." },
    { question: "Dans l'Apocalypse, que représentent symboliquement les '144 000' scellés ?", options: ["Exactement 144 000 Juifs convertis", "La totalité du peuple de Dieu (12 tribus × 12 × 1000)", "Les martyrs chrétiens des premiers siècles", "Les anges gardiens d'Israël"], correct: 1, explanation: "144 000 = 12 × 12 × 1000, nombre symbolique représentant la plénitude du peuple de Dieu." },
    { question: "Quel double commandement résume toute la Loi selon Jésus en Matthieu 22:37-40 ?", options: ["Aimer Dieu et son prochain (Deut 6:5 et Lév 19:18)", "Croire en Dieu et obéir à ses commandements", "Honorer ses parents et ne pas tuer", "La foi et les œuvres"], correct: 0, explanation: "Jésus cite Deutéronome 6:5 et Lévitique 19:18 comme résumé de toute la Loi (Matthieu 22:37-40)." },
    { question: "Quel terme hébreu de l'AT signifiant 'justice/droiture' est plus relationnel que légaliste ?", options: ["Mishpat", "Tsedaqah", "Torah", "Shalom"], correct: 1, explanation: "'Tsedaqah' (צְדָקָה) est la justice/droiture de Dieu dans l'alliance, impliquant fidélité, loyauté et action juste." },
    { question: "Quel est le paradoxe théologique au cœur de 2 Corinthiens 5:21 ?", options: ["La kénose du Christ", "L'échange divin où Christ prend notre péché et nous donne sa justice", "La sanctification progressive", "La résurrection comme victoire sur le péché"], correct: 1, explanation: "2 Corinthiens 5:21 exprime l'échange merveilleux : Christ est fait péché pour que nous devenions justice de Dieu." },
    { question: "Dans la LXX (Septante), par quel terme grec le nom divin YHWH est-il habituellement traduit ?", options: ["Theos (Dieu)", "Kyrios (Seigneur)", "Adonai (Mon Seigneur)", "El Shaddaï"], correct: 1, explanation: "La Septante traduit le tétragramme YHWH par 'Kyrios' (Κύριος, Seigneur)." },
    { question: "Quel est le sens hébreu du terme 'dabar' (דָּבָר) utilisé pour 'Parole de Dieu' dans les textes prophétiques ?", options: ["Simple communication verbale", "Parole/événement d'une puissance créatrice et efficace, réalisant ce qu'elle dit", "Commandement sans force propre", "Métaphore poétique du divin"], correct: 1, explanation: "'Dabar' (דָּבָר) désigne à la fois la parole ET l'événement/acte — la Parole de Dieu réalise ce qu'elle dit (Ésaïe 55:11 : 'elle ne reviendra pas à moi sans effet'). Le terme sous-tend la théologie du Logos johannique." },
    { question: "Quel est le sens du terme grec 'aletheia' (vérité) dans Jean 14:6 et son rapport avec la christologie ?", options: ["La vérité objective philosophique", "La Vérité comme personne divine : Christ est la vérité révélatrice et rédemptrice incarnée", "La fidélité humaine à Dieu", "Un concept juridique de véracité"], correct: 1, explanation: "Dans Jean 14:6, 'aletheia' (ἀλήθεια) ne désigne pas une vérité abstraite mais une personne : 'Je suis... la vérité.' Christ est la vérité révélatrice (il révèle Dieu tel qu'il est) et rédemptrice (il libère du mensonge du péché). Contraire johannique : le diable est 'père du mensonge' (Jean 8:44)." },
    { question: "Quel est le sens du terme 'Maranatha' utilisé dans 1 Corinthiens 16:22 et la Didachè ?", options: ["'Dieu est avec nous' en araméen", "'Notre Seigneur, viens !' en araméen — cri eschatologique de l'espérance primitive", "'Paix et grâce' en hébreu", "'Amen, ainsi soit-il' en grec"], correct: 1, explanation: "'Maranatha' (מָרַן אֲתָא) est une translittération araméenne signifiant soit 'Notre Seigneur est venu' (Maran atha) soit 'Notre Seigneur, viens !' (Marana tha) — l'interprétation impérative ('Viens, Seigneur !') est généralement préférée. C'est le cri eschatologique de l'Église primitive pour le retour de Christ (cf. Apocalypse 22:20)." },
    { question: "Quelle figure de rhétorique est utilisée dans Ésaïe 55:12 quand 'les montagnes pousseront des cris de joie et les arbres battront des mains' ?", options: ["Métaphore", "Prosopopée (personnification)", "Hyperbole", "Synecdoque"], correct: 1, explanation: "C'est une prosopopée (personnification) : les éléments de la nature sont présentés comme des êtres vivants exprimant la joie de la libération divine (Ésaïe 55:12)." },
    { question: "Quel verset de l'AT est cité en Hébreux 1:5 pour prouver la filiation divine unique du Christ ?", options: ["Psaume 2:7", "Psaume 110:1", "2 Samuel 7:14", "Les deux : Psaume 2:7 et 2 Samuel 7:14"], correct: 3, explanation: "Hébreux 1:5 cite successivement Psaume 2:7 ('Tu es mon fils, je t'ai engendré aujourd'hui') et 2 Samuel 7:14 ('Je lui serai pour père') pour démontrer la supériorité du Fils sur les anges." },
    { question: "Quel terme néotestamentaire (Hébreux 4:12) qualifie la Parole de Dieu comme 'vivante et efficace' ?", options: ["Logos (Parole vivante)", "Rhéma (Parole active)", "Zôn kai energês (vivante et efficace)", "Pneumatikos (spirituelle)"], correct: 2, explanation: "Hébreux 4:12 dit que la Parole de Dieu est 'vivante et efficace' (ζῶσα καὶ ἐνεργής, zôsa kai energês), plus tranchante qu'une épée à deux tranchants." },
    { question: "Quel est le sens du terme grec 'metanoia' (repentance) dans les évangiles par rapport au simple regret ?", options: ["Un sentiment de remords passager", "Un changement radical d'orientation mentale, spirituelle et pratique — tournant existentiel vers Dieu", "Une pratique rituelle d'expiation", "Le simple aveu de ses fautes"], correct: 1, explanation: "'Metanoia' (μετάνοια, méta = après/changement + noein = penser) désigne un changement radical et total de direction mentale et existentielle — bien plus que le simple regret ('metamélomai'). Jean-Baptiste et Jésus proclament la metanoia comme condition d'entrée dans le Royaume (Matthieu 3:2 ; 4:17)." },
    { question: "Quelle est la signification de la formule baptismale 'au nom du Père, du Fils et du Saint-Esprit' (Matthieu 28:19) dans la théologie trinitaire ?", options: ["Trois baptêmes séparés pour chaque personne divine", "Un seul baptême en un seul 'Nom' (au singulier) trinitaire — témoignant de l'unité et de la tripersonalité de Dieu", "Une formule liturgique sans portée dogmatique", "Un développement post-apostolique absent du NT primitif"], correct: 1, explanation: "Matthieu 28:19 : 'au nom' (eis to onoma, au singulier) du Père, du Fils et du Saint-Esprit — le singulier 'nom' (non 'noms') témoigne de l'unité divine dans la triple distinction personnelle. Ce verset est un des fondements de la doctrine trinitaire et fut utilisé dès les premiers conciles contre l'arianisme." },
    { question: "Quel est le sens de 'sabbat' dans son étymologie hébraïque et sa portée théologique ?", options: ["Repos physique seulement", "'Shabbat' (שַׁבָּת) vient de 'cesser/s'arrêter' — le repos de Dieu après la création modèle un rythme de grâce, libération de l'esclavage du travail et avant-goût eschatologique", "Un commandement purement légal et non théologique", "Un rite de purification hebdomadaire"], correct: 1, explanation: "'Shabbat' (שַׁבָּת) vient du verbe 'shavat' (cesser, s'arrêter). Le sabbat a trois dimensions : création (Genèse 2:2-3 — Dieu se repose, modèle d'imitation) ; libération (Deutéronome 5:15 — souvenir de la délivrance d'Égypte) ; eschatologie (Hébreux 4:9-11 — avant-goût du repos eschatologique en Christ)." },
    { question: "Quel est le sens de l'expression 'Esprit de vérité' (Pneuma tês alêtheias) dans le discours du Paraclet en Jean 16:13 ?", options: ["L'Esprit qui enseigne des vérités philosophiques", "L'Esprit Saint qui conduit dans toute la vérité révélée en Christ, rappelle les paroles de Jésus et révèle les choses à venir", "Un titre poétique de la sagesse divine", "L'esprit humain honnête et sincère"], correct: 1, explanation: "Jean 16:13 : 'Quand le Paraclet sera venu, l'Esprit de vérité, il vous conduira dans toute la vérité.' L'Esprit accomplit 4 fonctions herméneutiques : (1) conduit dans TOUTE la vérité ; (2) ne parle pas de lui-même ; (3) annonce les choses à venir ; (4) glorifie Christ. La 'vérité' désigne ici la révélation christologique plénière." },
    { question: "Quelle est la portée de l'image de 'l'agneau de Dieu' (Jean 1:29) dans le contexte de la Pâque et du Serviteur Souffrant ?", options: ["Uniquement un symbole de douceur", "Convergence entre l'agneau pascal (Exode 12), le Serviteur Souffrant (Ésaïe 53:7), les sacrifices quotidiens et l'Agneau cosmique de l'Apocalypse", "Un titre de majesté royale", "Une référence au bouc émissaire de Lévitique 16"], correct: 1, explanation: "L'image de l'agneau en Jean 1:29 est une convergence typologique : (1) Agneau pascal (protection par le sang, Exode 12) ; (2) Serviteur Souffrant conduit 'comme un agneau à la boucherie' (Ésaïe 53:7) ; (3) Sacrifice quotidien du Temple (tamid) ; (4) L'Agneau de l'Apocalypse 'comme immolé' regnant éternellement (Apocalypse 5:6). Jean-Baptiste concentre en deux mots ('Agneau de Dieu') toute la théologie sacrificielle de l'AT." },
    { question: "Quelle est la signification du terme 'propitiation' (hilastêrion) dans Romains 3:25 et son rapport avec le couvercle de l'Arche (kapporeth) ?", options: ["Une simple métaphore de pardon", "Le 'propitiatoire' ou siège de miséricorde : lieu où le sang expiateur était aspergé sur l'Arche — Jésus en est l'accomplissement en sa propre personne", "Un terme philosophique grec sans lien avec l'AT", "Un rite pénitentiel humain"], correct: 1, explanation: "Romains 3:25 utilise 'hilastêrion' (ἱλαστήριον) — le même terme que la LXX utilise pour le 'kapporeth' (כַּפֹּרֶת), le couvercle d'or de l'Arche sur lequel le Grand Prêtre aspergeait le sang le jour de Yom Kippour (Lévitique 16:14-15). Paul dit que Dieu a présenté Christ publiquement comme CE lieu de propitiation — en plein jour, non dans le Saint des Saints inaccessible." },
    { question: "Quel est le rapport entre Jean 3:14-15 et la figure du serpent d'airain en Nombres 21 ?", options: ["Simple comparaison rhétorique sans profondeur typologique", "Type-antitype : le serpent d'airain élevé (Nombres 21:8) préfigure exactement le Christ élevé sur la croix — regarder = croire = vivre", "Une référence cryptique inexpliquée", "Une parabole sur le péché seulement"], correct: 1, explanation: "Jean 3:14-15 : 'De même que Moïse a élevé le serpent dans le désert, il faut de même que le Fils de l'homme soit élevé, afin que quiconque croit en lui ait la vie éternelle.' Parfaite correspondance typologique : (1) le serpent élevé sur un bâton → Christ élevé sur la croix ; (2) les mordus par les serpents → les blessés par le péché ; (3) regarder en foi pour être guéri → croire pour avoir la vie éternelle." },
    { question: "Quelle est la signification du terme 'mystère' (mustêrion) chez Paul dans Éphésiens 3:6 ?", options: ["Un secret ésotérique réservé aux initiés", "Ce qui était caché dans les âges passés et révélé maintenant : Gentils cohéritiers avec Israël dans le seul Corps du Christ", "Un dogme incompréhensible", "Un rite liturgique secret"], correct: 1, explanation: "'Mustêrion' (μυστήριον) chez Paul ne désigne pas un secret ésotérique mais une révélation divine progressivement accomplie : 'les nations sont cohéritières, membres du même corps et participantes à la même promesse en Jésus-Christ' (Éphésiens 3:6). Ce mystère 'caché de tout temps en Dieu' est maintenant pleinement révélé par l'Évangile — l'unité de Juifs et de Gentils dans un seul Corps." },
    { question: "Quelle est la portée du terme grec 'telos' dans Matthieu 5:48 ('soyez parfaits comme votre Père céleste est parfait') ?", options: ["Perfection morale absolue impossible à atteindre", "'Telos' = complet, accompli, mature, orienté vers son but final — appel à la maturité et à l'intégrité dans l'amour", "Synonyme de 'saint' (hagios)", "Un idéal platonicien d'excellence morale"], correct: 1, explanation: "'Teleios' (τέλειος) vient de 'telos' (but, accomplissement) — non la perfection absolue sans défaut, mais la maturation, l'intégrité, l'amour accompli. Le contexte (Matthieu 5:43-48) porte sur aimer ses ennemis comme Dieu aime tous — l'idéal est l'amour sans exclusion, non une perfection légaliste." },
    { question: "Quel est le sens du terme 'dikaiosynê' (justice/droiture) dans le Sermon sur la Montagne (Matthieu 5:6,10,20 ; 6:33) ?", options: ["La justice légale rétributive", "La justice-alliance de Dieu : à la fois don reçu par grâce ET justice à pratiquer — dimension double de la justice du Royaume", "Uniquement la justice sociale horizontale", "La justification paulinienne uniquement"], correct: 1, explanation: "'Dikaiosynê' dans Matthieu a une double dimension : (1) verticale — la justice que Dieu donne (5:6 : affamés de justice) ; (2) horizontale — la justice à pratiquer envers les autres (5:10 : persécutés pour la justice). Matthieu 5:20 ('si votre justice ne surpasse pas celle des scribes et des Pharisiens') désigne une justice de l'intention du cœur, non seulement de l'observance externe." },
    { question: "Quelle est la signification liturgique et eschatologique de l'expression 'Corps et Sang du Christ' dans 1 Corinthiens 11:23-26 ?", options: ["Un simple repas commémoratif sans présence réelle", "'Faites ceci en mémoire de moi' institue une anamnèse (mémorial actif) proclamant la mort du Seigneur jusqu'à ce qu'il vienne — tension entre passé (croix), présent (repas) et futur (Parousie)", "La transsubstantiation catholique exactement", "Un repas agapé fraternel seulement"], correct: 1, explanation: "1 Corinthiens 11:26 : 'Toutes les fois que vous mangez ce pain et que vous buvez cette coupe, vous annoncez la mort du Seigneur, jusqu'à ce qu'il vienne.' La Cène est une anamnèse (ἀνάμνησις) — non simple souvenir passif, mais proclamation active tenant ensemble : la croix (passé, fondement), la présence du Ressuscité (présent, participation) et la Parousie (futur, espérance)." },
    { question: "Quel est le sens théologique du 'nom au-dessus de tout nom' accordé à Jésus en Philippiens 2:9-11 ?", options: ["Un titre honorifique humain", "L'exaltation eschatologique de Jésus recevant le nom divin YHWH lui-même — accomplissement d'Ésaïe 45:23 appliqué au Christ", "Simplement le nom 'Jésus'", "Un titre de gloire angélique"], correct: 1, explanation: "Philippiens 2:9-11 cite Ésaïe 45:23 ('devant moi tout genou se pliera et toute langue jurera') — verset parlant de YHWH lui-même dans Isaïe — et l'applique à Jésus. Le 'nom au-dessus de tout nom' est le Nom divin YHWH = Seigneur (Kyrios). L'exaltation de Christ est son investiture du Nom et de l'autorité divine sur toute la création." },
    { question: "Quelle est la portée universelle et christocentrique de la 'nouvelle création' (ktisis kainê) en 2 Corinthiens 5:17 ?", options: ["Uniquement un changement moral intérieur", "La nouvelle création cosmique inaugurée en Christ ressuscité, dont le croyant participe maintenant par anticipation eschatologique", "La création d'une nouvelle Église", "Le renouvellement annuel de la nature"], correct: 1, explanation: "2 Corinthiens 5:17 : 'Si quelqu'un est en Christ, il est une nouvelle création. Les choses anciennes sont passées ; voici, toutes choses sont devenues nouvelles.' 'Ktisis kainê' renvoie à la promesse d'Ésaïe d'un 'nouveau ciel et une nouvelle terre' (Ésaïe 65:17). Christ ressuscité est 'les prémices' (1 Corinthiens 15:20) de la nouvelle création cosmique — le croyant y participe déjà en espérance." },
    { question: "Quelle est la relation entre les 'promesses d'Abraham' en Galates 3 et la portée universelle de la bénédiction divine ?", options: ["Les promesses s'adressent uniquement à Israël", "Paul montre que la promesse à Abraham ('toutes les nations bénies en toi', Genèse 12:3 ; 22:18) précède la Loi de 430 ans et trouve son accomplissement uniquement en Christ", "Les promesses sont abolies par la Loi", "Les Gentils héritent par la circoncision"], correct: 1, explanation: "Galates 3:15-18 : La promesse abrahamique (Genèse 12:3 ; 22:18) est antérieure et supérieure à la Loi (430 ans après, Exode 12:40). Paul dit en 3:16 que la promesse est faite 'à ta descendance' (au singulier) = Christ. Par l'union avec Christ, Juifs ET Gentils deviennent 'descendance d'Abraham, héritiers selon la promesse' (Galates 3:29) — accomplissement cosmique de la bénédiction universelle." },
    { question: "Quel est le sens de l'image des 'cieux nouveau et terre nouvelle' dans Apocalypse 21:1 et comment diffère-t-il de l'annihilation cosmique ?", options: ["Destruction totale de l'univers et création ex nihilo d'un autre", "Le terme grec 'kainos' (nouveau en qualité) indique une transformation transfiguratrice, non une annihilation — continuité dans la discontinuité", "Une simple métaphore spirituelle du cœur renouvelé", "L'annihilation exacte de l'AT (2 Pierre 3:10-12)"], correct: 1, explanation: "Apocalypse 21:1 utilise 'kainos' (καινός, nouveau en qualité) non 'neos' (nouveau en temps). 2 Pierre 3:10-12 parle de 'dissolution' mais le terme grec 'lythêsontai' peut signifier 'être défaits/transformés' non nécessairement 'annihilés'. Romains 8:21 dit que 'la création elle-même sera affranchie de la servitude' — mouvement de libération, non d'annihilation. La résurrection du corps physique de Christ soutient la continuité corporelle de la nouvelle création." },
    { question: "Quel est le sens de la 'préordination/prédestination' (proorizô) en Romains 8:29-30 et comment la théologie réformée le distingue-t-elle de la simple prescience ?", options: ["Prédestination = Dieu décide en avance ce qu'il sait à l'avance (prescience), les deux sont identiques", "Prédestination = acte souverain de Dieu qui précède et cause la foi ; Prescience = connaissance de ce que Dieu a décrété — la prédestination logiquement avant la prescience", "La prédestination concerne uniquement Israël comme nation", "Paul ne distingue pas prédestination et prescience en Romains 8"], correct: 1, explanation: "La théologie réformée (Calvin) distingue : 'proginôskô' (prē-connaître, prescience) et 'proorizô' (pré-délimiter, prédestiner). Romains 8:29-30 : 'ceux qu'il a connus (proegnô) d'avance... il les a aussi prédestinés (proôrisen).' Pour la théologie réformée, la 'préconnaissance' est relationnelle (élire dans l'amour) et précède logiquement la 'prescience' — Dieu prédestine souverainement, il ne réagit pas à ce qu'il prévoit." },
    { question: "Quelle est la portée de Genèse 1:26-27 ('faisons l'homme à notre image et ressemblance') pour l'anthropologie biblique ?", options: ["Un vestige polythéiste (pluriel des dieux)", "L'imago Dei : l'homme comme être relationnel portant la ressemblance divine — capacité de relation avec Dieu, raison, créativité, responsabilité éthique et vocation royale sur la création", "La création de l'âme immortelle seulement", "Une métaphore de la formation physique de l'homme par Dieu"], correct: 1, explanation: "Genèse 1:26-27 est le fondement de l'anthropologie biblique. 'Image' (tselem) et 'ressemblance' (demut) désignent : (1) relation avec Dieu (capacité d'entente et de réponse) ; (2) représentation/vice-régence (l'homme comme représentant de Dieu sur la création) ; (3) différence sexuée ('homme et femme, il les créa') comme reflet de la communion intradivine. Le pluriel 'faisons' est vu comme pluriel de majesté ou proto-trinitaire selon les interprètes." }
  ]
};